<template>  <view class="page">    <view class="card">      <view class="avatar-row" @click="chooseAvatar">        <text class="label">头像</text>        <view class="avatar-wrap">          <image class="avatar" :src="form.header || defaultAvatar" mode="aspectFill" />          <text class="avatar-tip">点击更换</text>        </view>      </view>      <view class="field">        <text class="label">昵称</text>        <input v-model="form.nickname" maxlength="64" placeholder="昵称" />      </view>      <view class="field">        <text class="label">性别</text>        <radio-group @change="onGenderChange">          <label class="radio-item"><radio value="0" :checked="form.gender === 0" />未知</label>          <label class="radio-item"><radio value="1" :checked="form.gender === 1" />男</label>          <label class="radio-item"><radio value="2" :checked="form.gender === 2" />女</label>        </radio-group>      </view>      <view class="field">        <text class="label">个性签名</text>        <textarea v-model="form.sign" maxlength="200" placeholder="写点什么..." />      </view>      <button class="save-btn" :loading="saving" @click="save">保存</button>    </view>  </view></template><script setup lang="ts">import {onShow} from '@dcloudio/uni-app'import {reactive, ref} from 'vue'import {uploadImage} from '@/api/image'import {fetchMemberInfo, updateMemberProfile} from '@/api/member'import {isLogin, setMember} from '@/stores/member'const saving = ref(false)const uploading = ref(false)const defaultAvatar = 'https://img.yzcdn.cn/vant/cat.jpeg'const form = reactive({  nickname: '',  header: '',  gender: 0,  sign: ''})async function load() {  if (!isLogin()) {    uni.navigateTo({ url: '/pages/login/index' })    return  }  const member = await fetchMemberInfo()  form.nickname = member.nickname || ''  form.header = member.header || ''  form.gender = member.gender ?? 0  form.sign = member.sign || ''}function onGenderChange(e: { detail: { value: string } }) {  form.gender = Number(e.detail.value)}function chooseAvatar() {  if (uploading.value) return  uni.chooseImage({    count: 1,    sizeType: ['compressed'],    sourceType: ['album', 'camera'],    success: async (res) => {      const filePath = res.tempFilePaths[0]      if (!filePath) return      uploading.value = true      uni.showLoading({ title: '上传中' })      try {        const result = await uploadImage(filePath)        form.header = result.displayUrl || result.permanentUrl || result.objectName      } catch (e) {        uni.showToast({ title: (e as Error).message, icon: 'none' })      } finally {        uploading.value = false        uni.hideLoading()      }    }  })}async function save() {  saving.value = true  try {    const member = await updateMemberProfile({      nickname: form.nickname,      header: form.header || undefined,      gender: form.gender,      sign: form.sign    })    setMember(member)    uni.showToast({ title: '保存成功' })    setTimeout(() => uni.navigateBack(), 500)  } catch (e) {    uni.showToast({ title: (e as Error).message, icon: 'none' })  } finally {    saving.value = false  }}onShow(load)</script><style scoped>.page {  padding: 24rpx;  min-height: 100vh;  background: #f5f5f5;}.card {  padding: 32rpx;  background: #fff;  border-radius: 16rpx;}.avatar-row {  display: flex;  align-items: center;  justify-content: space-between;  margin-bottom: 28rpx;  padding-bottom: 28rpx;  border-bottom: 1rpx solid #f0f0f0;}.avatar-wrap {  display: flex;  flex-direction: column;  align-items: center;  gap: 8rpx;}.avatar {  width: 120rpx;  height: 120rpx;  border-radius: 50%;  background: #f5f5f5;}.avatar-tip {  font-size: 22rpx;  color: #1677ff;}.field {  margin-bottom: 28rpx;}.label {  display: block;  margin-bottom: 12rpx;  font-size: 26rpx;  color: #666;}input,textarea {  width: 100%;  padding: 16rpx 20rpx;  background: #f5f5f5;  border-radius: 12rpx;  font-size: 28rpx;  box-sizing: border-box;}textarea {  min-height: 160rpx;}.radio-item {  display: inline-flex;  align-items: center;  margin-right: 32rpx;  font-size: 28rpx;}.save-btn {  margin-top: 16rpx;  background: #1677ff;  color: #fff;  border-radius: 12rpx;}</style>